// // When NPCsrc is high, concatenate the lower four bits of PC4 with the upper 26 bits of I26 and append two ones. When NPCsrc is low, add PC4 to a sign-extended version of the upper 16 bits of I26, shifted right by two bits.
module top_module(
    input NPCsrc,
    input [31:0] PC4,
    input [25:0] I26,
    output [31:0] NPC
    );assign NPC = (NPCsrc==1) ? {PC4[31:28],I26[25:0],2'b00} : (PC4 + {{14{I26[15]}},I26[15:0],2'b00});

endmodule
